import React, { useEffect, useMemo, useState } from 'react';
import { useAuth } from '../auth/AuthContext';
import { apiRequest } from '../api/client';

const initialDonor = {
  donation_type: 'BOTH',
  organ_types: 'KIDNEY',
  preferred_donation_time: 'MORNING',
  profile: {
    first_name: '',
    last_name: '',
    date_of_birth: '1990-01-01',
    gender: 'OTHER',
    address: '',
    city: '',
    state: '',
    postal_code: '',
    country: 'India',
    latitude: '19.0760',
    longitude: '72.8777',
    blood_group: 'O+',
    emergency_contact_name: '',
    emergency_contact_phone: '',
  },
};

const initialFilters = {
  radiusKm: '50',
  maxDistanceKm: '100',
  urgency: '',
  bloodGroup: '',
};

const defaultProfileExtras = {
  headline: '',
  occupation: '',
  language: 'English',
  contact_preference: 'PHONE',
  timezone: 'Asia/Kolkata',
  bio: '',
};

function getStoredObject(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return fallback;
  try {
    return { ...fallback, ...JSON.parse(raw) };
  } catch (error) {
    return fallback;
  }
}

function deriveDonationType(donor) {
  const blood = Boolean(donor?.can_donate_blood);
  const organ = Boolean(donor?.organ_types?.length) || Boolean(donor?.organ_donation_registered);
  if (blood && organ) return 'BOTH';
  if (blood) return 'BLOOD';
  if (organ) return 'ORGAN';
  return 'BLOOD';
}

function addDays(days) {
  const dt = new Date();
  dt.setDate(dt.getDate() + days);
  return dt.toISOString().slice(0, 10);
}

function DonorPage({ view = 'medical-profile' }) {
  const { token, setFlash } = useAuth();

  const [form, setForm] = useState(initialDonor);
  const [authMe, setAuthMe] = useState(null);
  const [donorMe, setDonorMe] = useState(null);
  const [nearbyRequests, setNearbyRequests] = useState([]);
  const [topMatches, setTopMatches] = useState([]);
  const [filters, setFilters] = useState(initialFilters);
  const [profilePhoto, setProfilePhoto] = useState(() => localStorage.getItem('donor_profile_photo') || '');
  const [profileExtras, setProfileExtras] = useState(() => getStoredObject('donor_profile_extras', defaultProfileExtras));
  const [savingProfile, setSavingProfile] = useState(false);
  const [loading, setLoading] = useState(false);
  const [applyingRequestId, setApplyingRequestId] = useState('');
  const [appointmentPreference, setAppointmentPreference] = useState({
    date: addDays(1),
    time: '10:00',
    notes: 'Scheduled from donor dashboard.',
  });

  const verificationSummary = useMemo(() => {
    if (!authMe) return { complete: false, label: 'Pending' };
    const complete = Boolean(authMe.email_verified && authMe.phone_verified && authMe.id_verified);
    return { complete, label: complete ? 'Verified' : 'Pending' };
  }, [authMe]);

  const pageMeta = {
    'medical-profile': {
      title: 'Medical Profile',
      blurb: '',
    },
    'donation-history': {
      title: 'Donation History',
      blurb: '',
    },
    'nearby-requests': {
      title: 'Nearby Requests',
      blurb: '',
    },
    'appointment-scheduling': {
      title: 'Appointment Scheduling',
      blurb: '',
    },
    'matching-system': {
      title: 'Matching System',
      blurb: '',
    },
  };

  const activeMeta = pageMeta[view] || pageMeta['medical-profile'];
  const showIdentity = view === 'medical-profile';
  const showFilters = view === 'nearby-requests' || view === 'matching-system';
  const showNearby = view === 'nearby-requests';
  const showTopMatches = view === 'matching-system';
  const showDonationHistory = view === 'donation-history';
  const showAppointmentScheduling = view === 'appointment-scheduling';

  useEffect(() => {
    loadIdentity(true);
    loadDonorProfile(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function syncFormFromDonor(data) {
    if (!data) return;

    setForm((prev) => ({
      ...prev,
      donation_type: deriveDonationType(data),
      organ_types: (data.organ_types || []).join(', '),
      preferred_donation_time: data.preferred_donation_time || prev.preferred_donation_time,
      profile: {
        ...prev.profile,
        first_name: data.profile?.first_name || prev.profile.first_name,
        last_name: data.profile?.last_name || prev.profile.last_name,
        city: data.profile?.city || prev.profile.city,
        state: data.profile?.state || prev.profile.state,
        blood_group: data.profile?.blood_group || prev.profile.blood_group,
        latitude: data.profile?.latitude !== null && data.profile?.latitude !== undefined
          ? String(data.profile.latitude)
          : prev.profile.latitude,
        longitude: data.profile?.longitude !== null && data.profile?.longitude !== undefined
          ? String(data.profile.longitude)
          : prev.profile.longitude,
      },
    }));
  }

  function updateProfileField(field, value) {
    setForm((prev) => ({
      ...prev,
      profile: {
        ...prev.profile,
        [field]: value,
      },
    }));
  }

  function updateFormField(field, value) {
    setForm((prev) => ({ ...prev, [field]: value }));
  }

  function updateFilter(field, value) {
    setFilters((prev) => ({ ...prev, [field]: value }));
  }

  function updateAppointmentPreference(field, value) {
    setAppointmentPreference((prev) => ({ ...prev, [field]: value }));
  }

  function updateProfileExtra(field, value) {
    setProfileExtras((prev) => ({ ...prev, [field]: value }));
  }

  function onProfilePhotoSelected(event) {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      setFlash({ type: 'error', text: 'Please upload a valid image file.' });
      return;
    }

    const reader = new FileReader();
    reader.onload = () => {
      const photo = String(reader.result || '');
      setProfilePhoto(photo);
      localStorage.setItem('donor_profile_photo', photo);
      window.dispatchEvent(new CustomEvent('donor-photo-updated', { detail: photo }));
      setFlash({ type: 'success', text: 'Profile photo updated.' });
    };
    reader.readAsDataURL(file);
  }

  function clearProfilePhoto() {
    setProfilePhoto('');
    localStorage.removeItem('donor_profile_photo');
    window.dispatchEvent(new CustomEvent('donor-photo-updated', { detail: '' }));
    setFlash({ type: 'success', text: 'Profile photo removed.' });
  }

  function parseDonationPreferences() {
    const donationType = (form.donation_type || '').toUpperCase();
    const organTypes = form.organ_types
      .split(',')
      .map((x) => x.trim().toUpperCase())
      .filter(Boolean);

    if (donationType === 'BLOOD') {
      return { canDonateBlood: true, organDonationRegistered: false, organTypes: [] };
    }
    if (donationType === 'ORGAN') {
      return { canDonateBlood: false, organDonationRegistered: true, organTypes };
    }
    return { canDonateBlood: true, organDonationRegistered: true, organTypes };
  }

  async function loadIdentity(silent = false) {
    try {
      const data = await apiRequest('/auth/me', { token });
      setAuthMe(data);
    } catch (error) {
      if (!silent) setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadDonorProfile(silent = false) {
    try {
      const data = await apiRequest('/donors/me', { token });
      setDonorMe(data);
      syncFormFromDonor(data);
    } catch (error) {
      if (error?.status === 404) {
        setDonorMe(null);
        return;
      }
      if (!silent) setFlash({ type: 'error', text: error.message });
    }
  }

  async function saveProfile(event) {
    event.preventDefault();
    setSavingProfile(true);

    try {
      const prefs = parseDonationPreferences();
      const basePayload = {
        can_donate_blood: prefs.canDonateBlood,
        organ_types: prefs.organTypes,
        organ_donation_registered: prefs.organDonationRegistered,
        preferred_donation_time: form.preferred_donation_time,
        profile: {
          ...form.profile,
          latitude: Number(form.profile.latitude),
          longitude: Number(form.profile.longitude),
        },
      };

      if (!donorMe) {
        await apiRequest('/donors/register', {
          method: 'POST',
          token,
          body: basePayload,
        });
      } else {
        await apiRequest('/donors/me/profile', {
          method: 'PUT',
          token,
          body: {
            donation_type: form.donation_type,
            ...basePayload,
          },
        });
      }

      localStorage.setItem('donor_profile_extras', JSON.stringify(profileExtras));
      if (profilePhoto) {
        localStorage.setItem('donor_profile_photo', profilePhoto);
      }

      setFlash({ type: 'success', text: 'Donor profile saved successfully.' });
      await loadIdentity(true);
      await loadDonorProfile(true);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setSavingProfile(false);
    }
  }

  async function toggleAvailability() {
    if (!donorMe) {
      setFlash({ type: 'error', text: 'Create your donor profile first.' });
      return;
    }

    try {
      await apiRequest('/donors/me/availability', {
        method: 'PUT',
        token,
        body: { is_available: !donorMe.is_available },
      });
      setFlash({ type: 'success', text: `Availability updated to ${!donorMe.is_available}.` });
      await loadDonorProfile(true);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  function captureLiveLocation() {
    if (!navigator.geolocation) {
      setFlash({ type: 'error', text: 'Geolocation is not supported by your browser.' });
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        updateProfileField('latitude', String(position.coords.latitude));
        updateProfileField('longitude', String(position.coords.longitude));
        setFlash({ type: 'success', text: 'Live location captured. Click "Save Location" to persist.' });
      },
      () => {
        setFlash({ type: 'error', text: 'Unable to capture location. Check browser permissions.' });
      }
    );
  }

  async function saveLocationOnly() {
    if (!donorMe) {
      setFlash({ type: 'error', text: 'Create donor profile first to persist location.' });
      return;
    }

    try {
      await apiRequest('/donors/me/profile', {
        method: 'PUT',
        token,
        body: {
          profile: {
            latitude: Number(form.profile.latitude),
            longitude: Number(form.profile.longitude),
          },
        },
      });
      setFlash({ type: 'success', text: 'Location updated successfully.' });
      await loadDonorProfile(true);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function loadNearbyRequests(silent = false) {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set('radius_km', filters.radiusKm || '50');
      if (filters.urgency) params.set('urgency', filters.urgency);
      if (filters.bloodGroup) params.set('blood_group', filters.bloodGroup);

      const data = await apiRequest(`/donors/me/nearby-requests?${params.toString()}`, { token });
      setNearbyRequests(data.items || []);
      if (!silent) {
        setFlash({ type: 'success', text: `Loaded ${data.count || 0} nearby requests.` });
      }
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (!showNearby || !token) {
      return;
    }
    loadNearbyRequests(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showNearby, token]);

  async function loadTopMatches(silent = false) {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      params.set('limit', '20');
      params.set('max_distance_km', filters.maxDistanceKm || '100');
      if (filters.urgency) params.set('urgency', filters.urgency);
      if (filters.bloodGroup) params.set('blood_group', filters.bloodGroup);

      const data = await apiRequest(`/donors/me/top-matches?${params.toString()}`, { token });
      setTopMatches(data.items || []);
      if (!silent) {
        setFlash({ type: 'success', text: `Loaded ${data.count || 0} top matches.` });
      }
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if ((!showTopMatches && !showDonationHistory) || !token) {
      return;
    }
    loadTopMatches(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showTopMatches, showDonationHistory, token]);

  async function acceptRequest(matchId) {
    try {
      await apiRequest(`/matches/${matchId}/accept`, {
        method: 'POST',
        token,
        body: {
          appointment_preferred_date: appointmentPreference.date || addDays(1),
          appointment_preferred_time: appointmentPreference.time || '10:00',
          notes: appointmentPreference.notes || 'Scheduled from donor dashboard.',
        },
      });
      setFlash({ type: 'success', text: 'Applied successfully.' });
      await loadNearbyRequests();
      await loadTopMatches();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  async function applyForRequest(item) {
    setApplyingRequestId(item.request_id);
    try {
      if (item.match_id) {
        await acceptRequest(item.match_id);
      } else {
        await apiRequest(`/requests/${item.request_id}/apply`, {
          method: 'POST',
          token,
        });
        setFlash({ type: 'success', text: 'Applied successfully.' });
        await loadNearbyRequests();
        await loadTopMatches();
      }
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setApplyingRequestId('');
    }
  }

  async function rejectRequest(matchId, ignore = false) {
    const reason = ignore
      ? 'IGNORED'
      : window.prompt('Reason for rejection', 'Unavailable at this time');

    if (!reason) return;

    try {
      await apiRequest(`/matches/${matchId}/reject`, {
        method: 'POST',
        token,
        body: {
          reason,
          details: ignore ? 'Ignored by donor from dashboard.' : reason,
        },
      });
      setFlash({ type: 'success', text: ignore ? 'Request ignored.' : 'Request rejected.' });
      await loadNearbyRequests();
      await loadTopMatches();
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    }
  }

  return (
    <section className="panel full donor-page">
      <div className="donor-hero">
        <div>
          <p className="eyebrow">Donor Workspace</p>
          <h2>{activeMeta.title}</h2>
          <p className="muted-text">{activeMeta.blurb}</p>
        </div>
        <div className="donor-hero-chips">
          <span className={`status-chip ${verificationSummary.complete ? 'good' : 'warn'}`}>
            Verification: {verificationSummary.label}
          </span>
          <span className={`status-chip ${donorMe?.is_available ? 'good' : 'warn'}`}>
            Availability: {donorMe ? (donorMe.is_available ? 'Available' : 'Not Available') : 'Not Set'}
          </span>
        </div>
      </div>

      {(showIdentity || showStatus) && (
        <div className={`donor-grid ${showIdentity && !showStatus ? 'single-col' : ''}`}>
          {showIdentity && (
            <article className="panel donor-section">
              {view === 'profile' ? (
                <>
                  <h3>Profile and Identity</h3>
                  <p className="muted-text">Add your photo and keep account details complete, just like modern donor platforms.</p>

                  <form onSubmit={saveProfile} className="donor-profile-layout">
                    <aside className="donor-profile-photo-card">
                      <div className="donor-profile-photo-preview">
                        {profilePhoto ? (
                          <img src={profilePhoto} alt="Donor profile" />
                        ) : (
                          <span>{form.profile.first_name?.[0] || 'D'}</span>
                        )}
                      </div>
                      <label className="btn-ghost donor-upload-btn">
                        Upload Photo
                        <input type="file" accept="image/*" onChange={onProfilePhotoSelected} hidden />
                      </label>
                      <button type="button" className="btn-ghost" onClick={clearProfilePhoto}>Remove Photo</button>
                    </aside>

                    <div className="donor-profile-fields">
                      <div className="donor-form-grid">
                        <input placeholder="First Name" value={form.profile.first_name} onChange={(e) => updateProfileField('first_name', e.target.value)} required />
                        <input placeholder="Last Name" value={form.profile.last_name} onChange={(e) => updateProfileField('last_name', e.target.value)} required />
                        <input type="date" value={form.profile.date_of_birth} onChange={(e) => updateProfileField('date_of_birth', e.target.value)} required />
                        <select value={form.profile.gender} onChange={(e) => updateProfileField('gender', e.target.value)}>
                          <option value="MALE">Male</option>
                          <option value="FEMALE">Female</option>
                          <option value="OTHER">Other</option>
                        </select>
                        <input placeholder="Address" value={form.profile.address} onChange={(e) => updateProfileField('address', e.target.value)} required />
                        <input placeholder="City" value={form.profile.city} onChange={(e) => updateProfileField('city', e.target.value)} required />
                        <input placeholder="State" value={form.profile.state} onChange={(e) => updateProfileField('state', e.target.value)} required />
                        <input placeholder="Postal Code" value={form.profile.postal_code} onChange={(e) => updateProfileField('postal_code', e.target.value)} />
                        <select value={form.profile.blood_group} onChange={(e) => updateProfileField('blood_group', e.target.value)}>
                          <option>O+</option>
                          <option>O-</option>
                          <option>A+</option>
                          <option>A-</option>
                          <option>B+</option>
                          <option>B-</option>
                          <option>AB+</option>
                          <option>AB-</option>
                        </select>
                        <select value={form.donation_type} onChange={(e) => updateFormField('donation_type', e.target.value)}>
                          <option value="BLOOD">Blood</option>
                          <option value="ORGAN">Organ</option>
                          <option value="BOTH">Both</option>
                        </select>
                        <input placeholder="Organs (comma separated)" value={form.organ_types} onChange={(e) => updateFormField('organ_types', e.target.value)} />
                        <select value={form.preferred_donation_time} onChange={(e) => updateFormField('preferred_donation_time', e.target.value)}>
                          <option value="MORNING">Morning</option>
                          <option value="AFTERNOON">Afternoon</option>
                          <option value="EVENING">Evening</option>
                          <option value="ANYTIME">Anytime</option>
                        </select>
                      </div>

                      <div className="donor-profile-extra-grid">
                        <input placeholder="Headline" value={profileExtras.headline} onChange={(e) => updateProfileExtra('headline', e.target.value)} />
                        <input placeholder="Occupation" value={profileExtras.occupation} onChange={(e) => updateProfileExtra('occupation', e.target.value)} />
                        <select value={profileExtras.language} onChange={(e) => updateProfileExtra('language', e.target.value)}>
                          <option value="English">English</option>
                          <option value="Hindi">Hindi</option>
                          <option value="Other">Other</option>
                        </select>
                        <select value={profileExtras.contact_preference} onChange={(e) => updateProfileExtra('contact_preference', e.target.value)}>
                          <option value="PHONE">Phone</option>
                          <option value="EMAIL">Email</option>
                          <option value="ANY">Any</option>
                        </select>
                        <input placeholder="Timezone" value={profileExtras.timezone} onChange={(e) => updateProfileExtra('timezone', e.target.value)} />
                        <textarea placeholder="Short Bio" value={profileExtras.bio} onChange={(e) => updateProfileExtra('bio', e.target.value)} rows={4} />
                        <input placeholder="Emergency Contact Name" value={form.profile.emergency_contact_name} onChange={(e) => updateProfileField('emergency_contact_name', e.target.value)} />
                        <input placeholder="Emergency Contact Phone" value={form.profile.emergency_contact_phone} onChange={(e) => updateProfileField('emergency_contact_phone', e.target.value)} />
                      </div>

                      <button type="submit" disabled={savingProfile}>
                        {savingProfile ? 'Saving...' : donorMe ? 'Save Profile' : 'Register and Save Profile'}
                      </button>
                    </div>
                  </form>
                </>
              ) : (
                <>
                  <h3>Account and Identity</h3>
                  <p className="muted-text">
                    Register or edit donor profile with blood group, organs, location, and preferences.
                  </p>

                  <form onSubmit={saveProfile} className="donor-form-grid">
                    <select value={form.donation_type} onChange={(e) => updateFormField('donation_type', e.target.value)}>
                      <option value="BLOOD">Blood</option>
                      <option value="ORGAN">Organ</option>
                      <option value="BOTH">Both</option>
                    </select>
                    <input placeholder="Organs (comma separated)" value={form.organ_types} onChange={(e) => updateFormField('organ_types', e.target.value)} />
                    <select value={form.preferred_donation_time} onChange={(e) => updateFormField('preferred_donation_time', e.target.value)}>
                      <option value="MORNING">Morning</option>
                      <option value="AFTERNOON">Afternoon</option>
                      <option value="EVENING">Evening</option>
                      <option value="ANYTIME">Anytime</option>
                    </select>
                    <input placeholder="First Name" value={form.profile.first_name} onChange={(e) => updateProfileField('first_name', e.target.value)} required />
                    <input placeholder="Last Name" value={form.profile.last_name} onChange={(e) => updateProfileField('last_name', e.target.value)} required />
                    <input type="date" value={form.profile.date_of_birth} onChange={(e) => updateProfileField('date_of_birth', e.target.value)} required />
                    <select value={form.profile.gender} onChange={(e) => updateProfileField('gender', e.target.value)}>
                      <option value="MALE">Male</option>
                      <option value="FEMALE">Female</option>
                      <option value="OTHER">Other</option>
                    </select>
                    <input placeholder="Address" value={form.profile.address} onChange={(e) => updateProfileField('address', e.target.value)} required />
                    <input placeholder="City" value={form.profile.city} onChange={(e) => updateProfileField('city', e.target.value)} required />
                    <input placeholder="State" value={form.profile.state} onChange={(e) => updateProfileField('state', e.target.value)} required />
                    <input placeholder="Postal Code" value={form.profile.postal_code} onChange={(e) => updateProfileField('postal_code', e.target.value)} />
                    <select value={form.profile.blood_group} onChange={(e) => updateProfileField('blood_group', e.target.value)}>
                      <option>O+</option>
                      <option>O-</option>
                      <option>A+</option>
                      <option>A-</option>
                      <option>B+</option>
                      <option>B-</option>
                      <option>AB+</option>
                      <option>AB-</option>
                    </select>
                    <input placeholder="Emergency Contact Name" value={form.profile.emergency_contact_name} onChange={(e) => updateProfileField('emergency_contact_name', e.target.value)} />
                    <input placeholder="Emergency Contact Phone" value={form.profile.emergency_contact_phone} onChange={(e) => updateProfileField('emergency_contact_phone', e.target.value)} />
                    <button type="submit" disabled={savingProfile}>{savingProfile ? 'Saving...' : donorMe ? 'Update Profile' : 'Register as Donor'}</button>
                  </form>
                </>
              )}
            </article>
          )}

          {showStatus && (
            <article className="panel donor-section">
              <h3>Availability and Status</h3>
              <p className="muted-text">Toggle availability and update live coordinates for matching.</p>

              <div className="donor-location-grid">
                <input placeholder="Latitude" value={form.profile.latitude} onChange={(e) => updateProfileField('latitude', e.target.value)} />
                <input placeholder="Longitude" value={form.profile.longitude} onChange={(e) => updateProfileField('longitude', e.target.value)} />
              </div>

              <div className="tab-row top-space">
                <button onClick={() => loadDonorProfile(false)}>Refresh Profile</button>
                <button onClick={toggleAvailability}>Toggle Available / Not Available</button>
                <button onClick={captureLiveLocation}>Use Live Location</button>
                <button onClick={saveLocationOnly}>Save Location</button>
              </div>

              <div className="donor-summary top-space">
                <div><strong>User Role:</strong> {authMe?.role || 'DONOR'}</div>
                <div><strong>Email Verified:</strong> {String(Boolean(authMe?.email_verified))}</div>
                <div><strong>Phone Verified:</strong> {String(Boolean(authMe?.phone_verified))}</div>
                <div><strong>ID Verified:</strong> {String(Boolean(authMe?.id_verified))}</div>
                <div><strong>Current City:</strong> {donorMe?.profile?.city || form.profile.city || '-'}</div>
                <div><strong>Preferred Donation:</strong> {form.donation_type}</div>
              </div>
            </article>
          )}
        </div>
      )}

      {showFilters && (
        <article className="panel donor-section">
          <h3>Matching and Requests</h3>
          <p className="muted-text">Filter by distance, urgency, and blood group.</p>

          <div className="donor-filter-grid">
            <input value={filters.radiusKm} onChange={(e) => updateFilter('radiusKm', e.target.value)} placeholder="Nearby radius km" />
            <input value={filters.maxDistanceKm} onChange={(e) => updateFilter('maxDistanceKm', e.target.value)} placeholder="Max match distance km" />
            <select value={filters.urgency} onChange={(e) => updateFilter('urgency', e.target.value)}>
              <option value="">All Urgency</option>
              <option value="LOW">LOW</option>
              <option value="MEDIUM">MEDIUM</option>
              <option value="CRITICAL">CRITICAL</option>
            </select>
            <select value={filters.bloodGroup} onChange={(e) => updateFilter('bloodGroup', e.target.value)}>
              <option value="">All Blood Groups</option>
              <option value="O+">O+</option>
              <option value="O-">O-</option>
              <option value="A+">A+</option>
              <option value="A-">A-</option>
              <option value="B+">B+</option>
              <option value="B-">B-</option>
              <option value="AB+">AB+</option>
              <option value="AB-">AB-</option>
            </select>
          </div>

          <div className="tab-row top-space">
            <button onClick={loadNearbyRequests} disabled={loading}>View Nearby Requests</button>
            <button onClick={loadTopMatches} disabled={loading}>View Top Matches</button>
          </div>
        </article>
      )}

      {(showNearby || showTopMatches) && (
        <div className={`donor-results-grid ${showNearby && !showTopMatches ? 'single-col' : ''}`}>
          {showNearby && (
            <article className="panel donor-section">
              <h3>Nearby Requests</h3>
              <p className="muted-text">Simple view: pick a request and click Apply.</p>
              {nearbyRequests.length === 0 && <p className="muted-text">No nearby requests loaded yet.</p>}

              {nearbyRequests.map((item) => (
                <div key={item.request_id} className="donor-request-card">
                  <div className="donor-card-head">
                    <strong>{item.request_type}</strong>
                    <span>{item.urgency_level}</span>
                  </div>
                  <p><strong>Hospital:</strong> {item.hospital_name || 'N/A'}</p>
                  <p><strong>Distance:</strong> {Number(item.distance_km).toFixed(2)} km</p>
                  <p><strong>Blood Group Needed:</strong> {item.blood_group_needed || '-'}</p>
                  <p><strong>Organ Needed:</strong> {item.organ_type_needed || '-'}</p>
                  <p><strong>Notes:</strong> {item.clinical_notes || 'No additional notes.'}</p>
                  <p><strong>Match Score:</strong> {item.compatibility_score !== null && item.compatibility_score !== undefined ? Number(item.compatibility_score).toFixed(2) : 'Auto-calculated on apply'}</p>

                  <div className="tab-row">
                    <button
                      onClick={() => applyForRequest(item)}
                      disabled={applyingRequestId === item.request_id}
                    >
                      {applyingRequestId === item.request_id ? 'Applying...' : 'Apply'}
                    </button>
                  </div>
                </div>
              ))}
            </article>
          )}

          {showTopMatches && (
            <article className="panel donor-section">
              <h3>Top Matches (Ranked)</h3>
              {topMatches.length === 0 && <p className="muted-text">No matches loaded yet.</p>}

              {topMatches.map((match, index) => (
                <div key={match.match_id} className="donor-request-card">
                  <div className="donor-card-head">
                    <strong>#{index + 1} | Score {Number(match.compatibility_score).toFixed(2)}</strong>
                    <span>{match.urgency_level}</span>
                  </div>
                  <p><strong>Hospital:</strong> {match.hospital_name || 'N/A'}</p>
                  <p><strong>Distance:</strong> {Number(match.distance_km).toFixed(2)} km</p>
                  <p><strong>Request Type:</strong> {match.request_type}</p>
                  <p><strong>Blood Group Needed:</strong> {match.blood_group_needed || '-'}</p>
                  <p><strong>Organ Needed:</strong> {match.organ_type_needed || '-'}</p>
                  <p><strong>Status:</strong> {match.match_status} / Donor Response: {match.donor_response}</p>
                  <p><strong>Notes:</strong> {match.clinical_notes || 'No additional notes.'}</p>

                  <div className="tab-row">
                    <button onClick={() => acceptRequest(match.match_id)}>Accept</button>
                    <button onClick={() => rejectRequest(match.match_id, false)}>Reject</button>
                    <button onClick={() => rejectRequest(match.match_id, true)}>Ignore</button>
                  </div>
                </div>
              ))}
            </article>
          )}
        </div>
      )}
    </section>
  );
}

export default DonorPage;
